<template>
	<view class="body">
		<view class="" style="height: 40rpx;">

		</view>
		<view class="box">
			<view class="from">
				<view class="item" style="margin-bottom: -20rpx;">
					<view class="label">
						订单编号
					</view>
					<view class="input">
						<u-input v-model="ordersn" disabled />
					</view>
				</view>

				<view class="item">
					<view class="label">
						售后主题
					</view>
					<view class="input" @click="show =true" style="height: 72rpx;line-height: 72rpx;">
					<!-- 	<view class="" v-if="is_have_complain">
							{{subject}}
						</view> -->

						<u-input  v-model="subject" placeholder="选择售后主题" :select-open="show"
							input-align="left" type="select" @click="show = true" />

						<u-select  v-model="show" :list="subjectList"
							@confirm="confirm"></u-select>
					</view>

				</view>
				<view class="item" v-if="complainList.length>0">

					<scroll-view scroll-y style="max-height: 632rpx;">
						<view class="complain-content">
							<view v-for="(item,index) in complainList" :key="index" class="content-box">

								<view class="con-box">
									<view class="top">
										<view class="type" :style="{
										color:item.type==1?'blue':'red',
										fontWeigh:'bold',
									}">
											{{item.type==1?'客服':'用户'}}
										</view>
										<view class="time">
											{{ $util.timeFormat(item.time,'yyyy-mm-dd hh:MM:ss') }}
										</view>
									</view>
									<view class="con">
										<image @click="previewImage($util.img(item.screenshot))" class="img"
											v-if="item.screenshot" :src="$util.img(item.screenshot)" mode="aspectFit">
										</image>
										<text class="text">
											{{item.content}}
										</text>
									</view>
								</view>
							</view>

						</view>
					</scroll-view>

				</view>
				<view class="item" v-if="!stop_complain">
					<view class="label">
						售后内容
					</view>

					<view class="input">
						<u-input v-model="content" :border="true" maxlength="255" :auto-height="false" :custom-style="{
						height:'180rpx',
					}" type="textarea" :height="80" />
					</view>
				</view>
				<view class="item" v-if="!stop_complain">
					<view class="label">
						售后图片
					</view>

					<view class="input">
						<u-upload ref="uUpload" :before-upload="beforeUpload" @on-success="uploadSuccess"
							:max-size="2097152" :show-progress="false" :max-count="1" :action="action" :header="header">
						</u-upload>
					</view>

				</view>
			</view>
			<view class="submit" v-if="!stop_complain">
				<view class="buy-button" @click="complain">
					提交
				</view>
			</view>
		</view>

	</view>
</template>


<script>
	import md5Libs from "uview-ui/libs/function/md5";
	import config from "common/config.js";
	export default {
		data() {
			return {
				action: '', //上传图片方法
				sys: this.$util.sys(),
				page: 1,
				limit: 10,
				ordersn: '',
				subject: '',
				type_id: 0,
				subjectList: [

				],
				complainList: [],
				show: false,
				content: '',
				screenshot: '',
				header: {


				},
				stop_complain: false,
				is_have_complain: true,

			}
		},


		onLoad(e) {


			if (e.ordersn) {
				this.ordersn = e.ordersn
				this.loadData();
			}
		},

		methods: {
			previewImage(url) { // index 索引 如果 需要复用方法 可以使用 类型来进行区分(val)

				uni.previewImage({
					current: 0, // 当前显示图片的索引值
					urls: [url], // 需要预览的图片列表，photoList要求必须是数组

				})
			},
			beforeUpload(index, list) {



				this.header.authorization = 'Bearer ' + uni.getStorageSync('token');

				this.header.sign = this.$util.reqSign()

				return true;
			},
			uploadSuccess(data, index, lists, name) {


				if (data.code == 200) {
					this.screenshot = data.data.src
				}
			},
			async loadData() {
				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				// let params = {};
				await this.$u.api.addcomplainConfig({
						ordersn: this.ordersn
					})
					.then(res => {

						this.subjectList = res.subjectList
						// for (let i = 0; i < res.subjectList.length; i++) {
						// 	this.subjectList.push({
						// 		label: res.subjectList[i],
						// 		value: i,
						// 	})
						// }

						this.complainList = res.complainList
						this.action = config.apiurl + '/uni/upload'



						if (res.complain.subject) {

							//终止售后
							if (res.complain.status == 4) {
								this.stop_complain = true;
							}

							this.subject = res.complain.subject
							this.is_have_complain = true
						} else {
							this.subject = this.subjectList[0].label
							this.type_id = this.subjectList[0].value

							this.is_have_complain = false
						}

					}).catch(res => {})

				// this.loading = false;
				uni.hideLoading()

			},
			confirm(e) {
				this.subject = e[0].label
				this.type_id = e[0].value
			},
			//提交售后
			async complain() {


				if (this.subject == '') {
					this.$util.msg('请选择售后主题');
					return;
				}
				if (this.content == '') {
					this.$util.msg('请填写售后内容');
					return;
				}


				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				await this.$u.api.addcomplain({
						screenshot: this.screenshot,
						content: this.content,
						ordersn: this.ordersn,
						subject: this.subject,
						type_id: this.type_id,
					})
					.then(res => {
						this.$util.msg('售后成功');
						this.loadData()
						// setTimeout(() => {
						// 	this.$util.back()
						// }, 1000)
					}).catch(res => {})
				uni.hideLoading()

			},






		}

	}
</script>

<style lang="scss" scoped scoped>
	page {
		background-color: #f4f5f8;
	}

	.body {
		display: flex;
		flex-direction: column;
		align-items: center;

		.box {
			background-color: #fff;
			padding: 20rpx;
			border-radius: 20rpx;

			.from {

				display: flex;
				flex-direction: column;
				gap: 20rpx;
				align-items: flex-start;
				// margin-top: 80rpx;

				.item {
					display: flex;
					width: 600rpx;

					align-items: center;
					justify-content: space-between;

					.input {
						width: 444rpx;
					}
				}
			}
		}

	}

	.buy-button {
		width: 620rpx;
		height: 92rpx;
		// background: linear-gradient(90deg, #FE8A55 0%, #FF5D4D 100%);
		background-color: #0e0d0d;
		border-radius: 48rpx;
		font-weight: 500;
		color: #fff;
		font-size: 32rpx;
		display: flex;
		justify-content: center;
		align-items: center;
		margin-top: 80rpx;
	}

	/deep/ .u-list-item {
		margin: 0px;
	}





	.complain-content {
		display: flex;
		align-items: center;
		flex-direction: column;
		gap: 20rpx;

		.content-box {
			width: 100%;
			;
			display: flex;
			align-items: center;
			flex-direction: column;
			gap: 20rpx;

			.con-box {
				width: 100%;
				;
				background-color: #f4f5f6;
				display: flex;
				align-items: center;
				flex-direction: column;
				gap: 20rpx;
				border-radius: 20rpx;
				padding: 20rpx;

				.top {
					width: 100%;
					display: flex;
					align-items: center;
					justify-content: space-between;
				}

				.con {
					width: 100%;
					display: flex;
					align-items: center;
					gap: 20rpx;

					.img {
						width: 80rpx;
						height: 80rpx;
					}

					.text {
						word-break: break-all;
						max-width: 462rpx;
					}
				}
			}
		}
	}
</style>